/**
 * Fleetsure — Fine-Tuning Script (Together AI)
 * ──────────────────────────────────────────────
 * Uploads the training dataset and starts fine-tuning on Together AI.
 * Run: node server/data/training/upload-and-train.js
 *
 * Prerequisites:
 * 1. TOGETHER_API_KEY in .env
 * 2. fleet-qa-pairs.jsonl generated by generate-dataset.js
 *
 * Together AI Fine-Tuning:
 * - Model: meta-llama/Meta-Llama-3.1-8B-Instruct-Reference
 * - Format: JSONL with {messages: [{role, content}]}
 * - Cost: ~$2-5 for 500 examples
 * - Time: 10-30 minutes
 */

import 'dotenv/config'
import { readFileSync, existsSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)
const DATASET_FILE = join(__dirname, 'fleet-qa-pairs.jsonl')

const TOGETHER_API = 'https://api.together.xyz/v1'
const BASE_MODEL = 'meta-llama/Meta-Llama-3.1-8B-Instruct-Reference'

async function togetherRequest(path, options = {}) {
  const apiKey = process.env.TOGETHER_API_KEY
  if (!apiKey) throw new Error('TOGETHER_API_KEY not set in .env')

  const url = `${TOGETHER_API}${path}`
  const res = await fetch(url, {
    ...options,
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      ...options.headers,
    },
  })

  if (!res.ok) {
    const err = await res.text()
    throw new Error(`Together API error (${res.status}): ${err}`)
  }

  return res.json()
}

async function uploadFile() {
  if (!existsSync(DATASET_FILE)) {
    throw new Error(`Dataset not found: ${DATASET_FILE}\nRun: node server/data/training/generate-dataset.js first`)
  }

  const content = readFileSync(DATASET_FILE, 'utf-8')
  const lines = content.trim().split('\n').length
  console.log(`Dataset: ${lines} training examples`)

  if (lines < 10) {
    throw new Error('Dataset too small. Need at least 10 examples for fine-tuning.')
  }

  console.log('Uploading dataset to Together AI...')

  const formData = new FormData()
  const blob = new Blob([content], { type: 'application/jsonl' })
  formData.append('file', blob, 'fleet-qa-pairs.jsonl')
  formData.append('purpose', 'fine-tune')

  const apiKey = process.env.TOGETHER_API_KEY
  const res = await fetch(`${TOGETHER_API}/files`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
    },
    body: formData,
  })

  if (!res.ok) {
    const err = await res.text()
    throw new Error(`Upload failed: ${err}`)
  }

  const data = await res.json()
  console.log(`File uploaded: ${data.id}`)
  return data.id
}

async function startFineTuning(fileId) {
  console.log(`\nStarting fine-tuning job...`)
  console.log(`Base model: ${BASE_MODEL}`)
  console.log(`Training file: ${fileId}`)

  const job = await togetherRequest('/fine-tunes', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      training_file: fileId,
      model: BASE_MODEL,
      n_epochs: 3,
      learning_rate: 1e-5,
      suffix: 'fleetsure-fleet-expert',
    }),
  })

  console.log(`\nFine-tuning job started!`)
  console.log(`Job ID: ${job.id}`)
  console.log(`Status: ${job.status}`)
  console.log(`\nMonitor progress at: https://api.together.xyz/playground`)
  console.log(`\nOnce complete, add to your .env:`)
  console.log(`FLEET_FINETUNED_MODEL=${job.output_name || '<model-name-from-together-dashboard>'}`)
  console.log(`TOGETHER_API_KEY=${process.env.TOGETHER_API_KEY}`)

  return job
}

async function checkStatus(jobId) {
  const job = await togetherRequest(`/fine-tunes/${jobId}`)
  console.log(`\nJob ${jobId}:`)
  console.log(`Status: ${job.status}`)
  if (job.output_name) {
    console.log(`Model: ${job.output_name}`)
    console.log(`\nAdd to .env: FLEET_FINETUNED_MODEL=${job.output_name}`)
  }
  return job
}

async function listJobs() {
  const jobs = await togetherRequest('/fine-tunes')
  console.log('\nFine-tuning jobs:')
  for (const job of (jobs.data || jobs)) {
    console.log(`  ${job.id} — ${job.status} — ${job.model} → ${job.output_name || '(pending)'}`)
  }
}

// ── CLI ──────────────────────────────────────────────────────────────────────

const command = process.argv[2] || 'run'

async function main() {
  switch (command) {
    case 'run': {
      const fileId = await uploadFile()
      await startFineTuning(fileId)
      break
    }
    case 'status': {
      const jobId = process.argv[3]
      if (!jobId) {
        await listJobs()
      } else {
        await checkStatus(jobId)
      }
      break
    }
    case 'list': {
      await listJobs()
      break
    }
    default:
      console.log('Usage:')
      console.log('  node upload-and-train.js run       # Upload dataset and start fine-tuning')
      console.log('  node upload-and-train.js status     # List all fine-tuning jobs')
      console.log('  node upload-and-train.js status <id> # Check specific job status')
  }
}

main().catch(err => {
  console.error('Error:', err.message)
  process.exit(1)
})
